# ----------------------------------------------------------------------------
# Google Sheets connection
# ----------------------------------------------------------------------------
@st.cache_resource(show_spinner=False)
def get_spreadsheet():
    scopes = [
        "https://www.googleapis.com/auth/spreadsheets",
        "https://www.googleapis.com/auth/drive",
    ]
    creds = Credentials.from_service_account_info(
        dict(st.secrets["gcp_service_account"]), scopes=scopes
    )
    gc = gspread.authorize(creds)
    return gc.open_by_key(st.secrets["app"]["spreadsheet_id"])


def ensure_ws(sh, title, headers):
    """Return worksheet `title`, creating it (with header row) if missing."""
    try:
        ws = sh.worksheet(title)
    except gspread.WorksheetNotFound:
        ws = sh.add_worksheet(title=title, rows=1000, cols=max(10, len(headers)))
        ws.update([headers])
        return ws
    if not ws.get_all_values():
        ws.update([headers])
    return ws


def read_records(title, headers):
    """Fresh (uncached) read of a worksheet's records. Used by write paths."""
    sh = get_spreadsheet()
    return ensure_ws(sh, title, headers).get_all_records()


def seed_fixtures(sh):
    """
    Add any SEASON_FIXTURES rounds that aren't yet in the sheet.

    Idempotent and non-destructive: rounds already present are left completely
    untouched, so existing predictions and entered results are preserved.
    Returns the number of fixture rows added.
    """
    fixtures_ws = ensure_ws(sh, "Fixtures", FIXTURES_HEADERS)
    existing = fixtures_ws.get_all_records()
    present_rounds = {to_int(f["round"]) for f in existing if to_int(f["round"]) is not None}

    rows = []
    for rnd in sorted(SEASON_FIXTURES):
        if rnd in present_rounds:
            continue  # already seeded — don't re-add or overwrite
        for i, (kickoff, home, away) in enumerate(SEASON_FIXTURES[rnd], start=1):
            rows.append([rnd, f"R{rnd}M{i}", kickoff, home, away, "", ""])

    if rows:
        fixtures_ws.append_rows(rows, value_input_option="USER_ENTERED")
    return len(rows)


def seed_if_empty(sh):
    """
    First-run setup: create the four tabs and backfill official fixtures.

    Phase 1 change: we NO LONGER seed TBA1..TBA10 placeholder players. A fresh
    install starts with an empty Players sheet; the organiser adds real players
    (or approves registrations). Any legacy TBA* rows are marked inactive by the
    schema migration instead.
    """
    ensure_ws(sh, "Players", PLAYERS_HEADERS)
    ensure_ws(sh, "Fixtures", FIXTURES_HEADERS)
    ensure_ws(sh, "Predictions", PREDICTIONS_HEADERS)
    ensure_ws(sh, "Registrations", REGISTRATIONS_HEADERS)

    # Backfill any missing rounds (adds rounds 2-8 to a sheet that only had Round 1;
    # seeds all 8 on a brand-new sheet). Existing rounds are never disturbed.
    added = seed_fixtures(sh)
    if added:
        refresh()


def migrate_schema(sh):
    """
    Add newer columns to existing sheets without touching any existing data.

    All steps are idempotent — they only act when a column is actually missing:
      * Players gains 'zoliky' (existing players backfilled with the starting 3).
      * Players gains 'active' (legitimate players -> yes; TBA* placeholders -> no).
      * Predictions gains 'zolik' (old rows read as 0 at load time).
    """
    a1 = gspread.utils.rowcol_to_a1

    pw = ensure_ws(sh, "Players", PLAYERS_HEADERS)
    vals = pw.get_all_values()
    if vals:
        header = vals[0]

        # --- zoliky column ---
        if "zoliky" not in header:
            col = len(header) + 1
            pw.update_cell(1, col, "zoliky")
            n = len(vals) - 1
            if n > 0:  # backfill existing players with the starting count
                rng = f"{a1(2, col)}:{a1(n + 1, col)}"
                pw.update(rng, [[DEFAULT_ZOLIKY] for _ in range(n)],
                          value_input_option="USER_ENTERED")
            vals = pw.get_all_values()
            header = vals[0] if vals else header

        # --- active column ---
        if "active" not in header:
            col = len(header) + 1
            pw.update_cell(1, col, "active")
            data_rows = vals[1:]
            if data_rows:
                code_idx = header.index("code") if "code" in header else 0
                name_idx = header.index("name") if "name" in header else 1
                backfill = []
                for r in data_rows:
                    code = r[code_idx] if len(r) > code_idx else ""
                    name = r[name_idx] if len(r) > name_idx else ""
                    backfill.append(["no" if is_placeholder(code, name) else "yes"])
                rng = f"{a1(2, col)}:{a1(len(data_rows) + 1, col)}"
                pw.update(rng, backfill, value_input_option="USER_ENTERED")

    prw = ensure_ws(sh, "Predictions", PREDICTIONS_HEADERS)
    pvals = prw.get_all_values()
    if pvals:
        header = pvals[0]
        if "zolik" not in header:
            prw.update_cell(1, len(header) + 1, "zolik")


@st.cache_resource(show_spinner=False)
def bootstrap():
    """Run idempotent sheet setup once per Streamlit server process."""
    sh = get_spreadsheet()
    seed_if_empty(sh)
    migrate_schema(sh)
    return sh


