# ----------------------------------------------------------------------------
# Basic helpers
# ----------------------------------------------------------------------------
def now():
    return datetime.now(TZ)


CZ_WEEKDAYS = ("po", "út", "st", "čt", "pá", "so", "ne")


def format_datetime_cz(dt):
    """Return a compact Prague-local date label without relying on OS locale."""
    local = dt.astimezone(TZ)
    return f"{CZ_WEEKDAYS[local.weekday()]} {local.day}. {local.month}. · {local:%H:%M}"


def format_saved_at_cz(value):
    """Format an ISO prediction timestamp as a compact Prague-local label."""
    try:
        dt = datetime.fromisoformat(str(value).strip())
    except (TypeError, ValueError):
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=TZ)
    else:
        dt = dt.astimezone(TZ)
    return format_datetime_cz(dt)


def parse_kickoff(s):
    """Parse an ISO kickoff string as Prague local time. Raises on bad input."""
    dt = datetime.fromisoformat(str(s))
    return dt.replace(tzinfo=TZ) if dt.tzinfo is None else dt.astimezone(TZ)


def parse_kickoff_safe(s):
    """Parse a kickoff string, returning None instead of raising on bad input."""
    try:
        return parse_kickoff(s)
    except (ValueError, TypeError):
        return None


def to_int(v):
    try:
        if v is None or str(v).strip() == "":
            return None
        return int(v)
    except (ValueError, TypeError):
        return None


def to_int_strict(v):
    """
    Like to_int but rejects floats/decimals and negatives.
    Returns None for blanks/invalid; used for real match scores.
    """
    if v is None:
        return None
    s = str(v).strip()
    if s == "":
        return None
    if not re.fullmatch(r"\d+", s):   # only non-negative integers, no '-', '.', etc.
        return None
    return int(s)


def sign(n):
    return (n > 0) - (n < 0)


# ----------------------------------------------------------------------------
# Canonical player-code normalization (Phase 1, section D)
# ----------------------------------------------------------------------------
def norm_code(code):
    """The one canonical player-code form used for every write and comparison."""
    return str(code).strip().upper()


def is_placeholder(code, name=""):
    """A legacy auto-seeded placeholder such as TBA1 / TBA7 (code or name)."""
    c = str(code).strip().upper()
    n = str(name).strip().upper()
    return bool(re.fullmatch(r"TBA\d*", c)) or bool(re.fullmatch(r"TBA\d*", n))


def to_bool(v):
    """Parse an 'active' cell. Blank -> None (caller decides the default)."""
    s = str(v).strip().lower()
    if s == "":
        return None
    if s in ("1", "true", "yes", "y", "ano", "active", "x", "t"):
        return True
    if s in ("0", "false", "no", "n", "ne", "inactive", "f"):
        return False
    return None  # unrecognised -> treated as invalid by validation


def player_active(p):
    """
    Whether a player row counts as active.

    An explicit active value wins. A blank value defaults to active UNLESS the
    row is an obvious placeholder (TBA*), which defaults to inactive. This keeps
    legitimate legacy rows (written before the 'active' column existed) working.
    """
    b = to_bool(p.get("active", ""))
    if b is None:
        return not is_placeholder(p.get("code", ""), p.get("name", ""))
    return b


# ----------------------------------------------------------------------------
# Scoring
# ----------------------------------------------------------------------------
def score_prediction(ph, pa, ah, aa):
    """Points for one predicted match. All args are ints."""
    if ph == ah and pa == aa:
        return 3
    if (ph - pa) == (ah - aa):          # same goal difference (includes draws)
        return 2
    if sign(ph - pa) == sign(ah - aa):  # right winner, wrong margin
        return 1
    return 0


def score_prediction_detailed(ph, pa, ah, aa):
    """
    Return (points, is_exact, is_goal_diff, is_winner).
    Hierarchical: exact score counts as all three.
    """
    if ph == ah and pa == aa:
        return (3, 1, 1, 1)    # exact score: counts for all three
    if (ph - pa) == (ah - aa):
        return (2, 0, 1, 1)    # goal diff: counts as diff + winner
    if sign(ph - pa) == sign(ah - aa):
        return (1, 0, 0, 1)    # just the winner
    return (0, 0, 0, 0)


# ----------------------------------------------------------------------------
# Fixture & player validation (Phase 1, section E)
# ----------------------------------------------------------------------------
def validate_fixtures(raw):
    """
    Validate raw Fixtures rows before any player-facing use.

    Returns (valid_fixtures, problems, rounds_with_issues):
      * valid_fixtures — structurally usable rows. Each is a dict with the
        original fields PLUS cleaned integer 'home_score'/'away_score' (set to
        None when the result is invalid or one-sided). Kept sorted-agnostic.
      * problems — list of (sheet_row_number, message) for the organiser.
      * rounds_with_issues — set of round numbers that had at least one problem.

    A fixture is EXCLUDED (unusable) when it lacks a valid round, has a
    missing/duplicate match_id, an unparseable kickoff, a missing team, or the
    same team on both sides. Result problems (negative/non-int/one-sided) do NOT
    exclude the fixture — the fixture stays usable for predictions and only its
    result is ignored (with a warning), because results arrive after fixtures.
    """
    problems = []
    rounds_with_issues = set()

    # First pass: find duplicate match_ids across the whole sheet.
    id_counts = {}
    for f in raw:
        mid = str(f.get("match_id", "")).strip()
        if mid:
            id_counts[mid] = id_counts.get(mid, 0) + 1
    dup_ids = {mid for mid, c in id_counts.items() if c > 1}

    valid = []
    for i, f in enumerate(raw):
        row = i + 2  # +1 header, +1 for 1-based sheet rows
        rnd = to_int(f.get("round"))
        mid = str(f.get("match_id", "")).strip()
        home = str(f.get("home", "")).strip()
        away = str(f.get("away", "")).strip()
        ko = parse_kickoff_safe(f.get("kickoff"))

        row_problems = []
        excluded = False

        if rnd is None:
            row_problems.append("chybí/neplatné číslo kola (round)")
            excluded = True
        if not mid:
            row_problems.append("chybí match_id")
            excluded = True
        elif mid in dup_ids:
            row_problems.append(f"duplicitní match_id '{mid}'")
            excluded = True
        if ko is None:
            row_problems.append("neplatný čas výkopu (kickoff)")
            excluded = True
        if not home:
            row_problems.append("chybí domácí tým")
            excluded = True
        if not away:
            row_problems.append("chybí hostující tým")
            excluded = True
        if home and away and home.lower() == away.lower():
            row_problems.append("stejný tým na obou stranách")
            excluded = True

        # Result checks (do not exclude the fixture; only the result is dropped).
        hs_raw, as_raw = f.get("home_score", ""), f.get("away_score", "")
        hs_blank = str(hs_raw).strip() == ""
        as_blank = str(as_raw).strip() == ""
        hs, as_ = None, None
        if not hs_blank or not as_blank:
            hs = to_int_strict(hs_raw)
            as_ = to_int_strict(as_raw)
            if (not hs_blank and hs is None) or (not as_blank and as_ is None):
                row_problems.append("neplatné skóre (musí být celé číslo ≥ 0)")
                hs, as_ = None, None
            elif hs_blank != as_blank:
                row_problems.append("zadána jen jedna strana výsledku")
                hs, as_ = None, None

        if row_problems:
            problems.append((row, "; ".join(row_problems)))
            if rnd is not None:
                rounds_with_issues.add(rnd)

        if excluded:
            continue

        clean = dict(f)
        clean["round"] = rnd
        clean["match_id"] = mid
        clean["home"] = home
        clean["away"] = away
        clean["home_score"] = hs
        clean["away_score"] = as_
        valid.append(clean)

    return valid, problems, rounds_with_issues


def validate_players(raw):
    """
    Validate raw Players rows.

    Returns (valid_players, problems):
      * valid_players — rows keeping first occurrence of each normalized code,
        with a cleaned integer 'zoliky' (clamped to [0, MAX_ZOLIKY]) and the
        original 'active' cell preserved.
      * problems — list of (sheet_row_number, message) for the organiser.

    Duplicate normalized codes: the first row is kept and used; later duplicates
    are dropped from play and flagged, so no player is ever double-counted.
    """
    problems = []
    valid = []
    seen = {}

    for i, p in enumerate(raw):
        row = i + 2
        raw_code = str(p.get("code", "")).strip()
        code = norm_code(raw_code)
        name = str(p.get("name", "")).strip()
        row_problems = []
        drop = False

        if not raw_code:
            row_problems.append("chybí kód hráče")
            drop = True
        elif code in seen:
            row_problems.append(f"duplicitní kód '{code}' (poprvé na řádku {seen[code]})")
            drop = True
        if not name:
            row_problems.append("chybí jméno")

        z = to_int(p.get("zoliky"))
        if p.get("zoliky", "") not in ("", None) and z is None:
            row_problems.append("neplatný počet žolíků")
        if z is None:
            z = DEFAULT_ZOLIKY
        if z < 0:
            row_problems.append("záporný počet žolíků")
            z = 0
        if z > MAX_ZOLIKY:
            row_problems.append(f"počet žolíků nad limit {MAX_ZOLIKY}")
            z = MAX_ZOLIKY

        if to_bool(p.get("active", "")) is None and str(p.get("active", "")).strip() != "":
            row_problems.append("neplatná hodnota 'active'")

        if row_problems:
            problems.append((row, "; ".join(row_problems)))

        if drop:
            continue

        seen[code] = row
        clean = dict(p)
        clean["code"] = code            # canonical uppercase for downstream use
        clean["name"] = name
        clean["zoliky"] = z
        valid.append(clean)

    return valid, problems


def active_players(players):
    """Valid players that are active (used for all scoring/visibility)."""
    return [p for p in players if player_active(p)]


# ----------------------------------------------------------------------------
# Round helpers (operate on VALIDATED fixtures)
# ----------------------------------------------------------------------------
def rounds_present(fixtures):
    return sorted({to_int(f["round"]) for f in fixtures if to_int(f["round"])})


def round_fixtures(fixtures, rnd):
    fs = [f for f in fixtures if to_int(f["round"]) == rnd]
    return sorted(fs, key=lambda f: parse_kickoff(f["kickoff"]))


def round_deadline(fixtures, rnd):
    fs = round_fixtures(fixtures, rnd)
    return min(parse_kickoff(f["kickoff"]) for f in fs) if fs else None


def is_locked(fixtures, rnd):
    dl = round_deadline(fixtures, rnd)
    return dl is not None and now() >= dl


def active_round(fixtures):
    """First round not yet locked; if all are locked, the last round present."""
    present = rounds_present(fixtures)
    if not present:
        return 1
    for r in present:
        if not is_locked(fixtures, r):
            return r
    return present[-1]


# ----------------------------------------------------------------------------
# Predictions: latest-per-key (codes normalized) + canonical žolík
# ----------------------------------------------------------------------------
def latest_predictions(predictions):
    """
    Dedupe append-only prediction rows: keep the newest per (code, round, match).

    Codes are normalized (upper) so mixed-case historical rows collapse onto the
    same canonical player. pred_home/pred_away are ints or None (None = the
    player never entered a score for that match — distinct from an entered 0).
    """
    best = {}
    for p in predictions:
        key = (norm_code(p["code"]), to_int(p["round"]), str(p["match_id"]))
        ts = str(p.get("updated_at", ""))
        if key not in best or ts >= best[key]["updated_at"]:
            best[key] = {
                "pred_home": to_int(p["pred_home"]),
                "pred_away": to_int(p["pred_away"]),
                "updated_at": ts,
                "zolik": to_int(p.get("zolik", 0)) or 0,
            }
    return best


def player_zoliky(players, code):
    """Number of jokers granted to a player (defaults to the starting count)."""
    c = norm_code(code)
    for p in players:
        if norm_code(p["code"]) == c:
            z = to_int(p.get("zoliky"))
            if z is None:
                return DEFAULT_ZOLIKY
            return max(0, min(z, MAX_ZOLIKY))
    return DEFAULT_ZOLIKY


def canonical_zolik_map(players, predictions):
    """
    THE single source of truth for which žolíks actually count (section C).

    For every player code we take their latest žolík selections and, if they
    exceed the player's granted allowance (e.g. because the organiser lowered
    it), we keep only the EARLIEST `granted` of them — ordered deterministically
    by (updated_at, round, match_id). Later excess selections are ignored for
    scoring but reported so the organiser can see them.

    Returns dict: code -> {
        'granted': int,
        'counted': set((round:int, match_id:str)),   # these double the points
        'excess':  list((round, match_id)),           # ignored for scoring
        'used_total': int,
    }
    """
    preds = latest_predictions(predictions)
    by_code = {}
    for (code, rnd, mid), v in preds.items():
        if v.get("zolik"):
            by_code.setdefault(code, []).append(
                (str(v.get("updated_at", "")), rnd if rnd is not None else 0, str(mid))
            )

    granted_lookup = {norm_code(p["code"]): player_zoliky(players, p["code"]) for p in players}
    codes = set(by_code) | set(granted_lookup)

    out = {}
    for code in codes:
        granted = granted_lookup.get(code, DEFAULT_ZOLIKY)
        sels = sorted(by_code.get(code, []), key=lambda t: (t[0], t[1], t[2]))
        counted = {(r, m) for _ts, r, m in sels[:granted]}
        excess = [(r, m) for _ts, r, m in sels[granted:]]
        out[code] = {"granted": granted, "counted": counted,
                     "excess": excess, "used_total": len(sels)}
    return out


def zolik_excess_report(players, predictions):
    """List of (code, name, granted, used_total, n_excess) for players over their allowance."""
    zmap = canonical_zolik_map(players, predictions)
    rows = []
    for code, info in zmap.items():
        if info["used_total"] > info["granted"]:
            rows.append((code, player_name(players, code), info["granted"],
                         info["used_total"], info["used_total"] - info["granted"]))
    return sorted(rows, key=lambda r: r[0])


def player_name(players, code):
    c = norm_code(code)
    for p in players:
        if norm_code(p["code"]) == c:
            return str(p["name"])
    return c


def player_exists_active(players, code):
    c = norm_code(code)
    for p in players:
        if norm_code(p["code"]) == c:
            return player_active(p)
    return False


# ----------------------------------------------------------------------------
# Leaderboard
# ----------------------------------------------------------------------------
def compute_leaderboard(players, fixtures, predictions):
    """
    Return a DataFrame with points and tie-breaking stats.

    Uses ONLY active players, VALIDATED fixtures (clean integer results), latest
    predictions per (code, round, match), and the canonical žolík map so that
    doubling matches what Results and Žolíci show. Malformed/incomplete
    predictions are ignored. Žolík doubles POINTS only — never the exact-score
    or goal-difference tie-break counts.

    Tie-breaking order:
      Total points > Exact scores > Goal differences > sheet order.
    If players remain tied at the end of the competition, the organiser resolves
    the final placing by draw as stated in the rules. The app keeps stable sheet
    order only as a temporary display order for otherwise identical records.
    """
    players = active_players(players)
    preds = latest_predictions(predictions)
    zmap = canonical_zolik_map(players, predictions)
    present = rounds_present(fixtures)

    # resolved matches per round (both real scores present & valid) in locked rounds
    resolved = {}
    for r in present:
        if not is_locked(fixtures, r):
            continue
        for f in round_fixtures(fixtures, r):
            ah, aa = f.get("home_score"), f.get("away_score")
            if ah is not None and aa is not None:
                resolved.setdefault(r, []).append((str(f["match_id"]), ah, aa))

    rows = []
    for pl in players:
        code, name = norm_code(pl["code"]), str(pl["name"])
        counted = zmap.get(code, {}).get("counted", set())
        row = {"Player": name}
        total = 0
        exact_count = 0
        goal_diff_count = 0

        for r in present:
            pts = 0
            for match_id, ah, aa in resolved.get(r, []):
                pr = preds.get((code, r, match_id))
                if pr and pr["pred_home"] is not None and pr["pred_away"] is not None:
                    p, is_exact, is_diff, _is_winner = score_prediction_detailed(
                        pr["pred_home"], pr["pred_away"], ah, aa
                    )
                    if (r, match_id) in counted:   # canonical žolík doubles points only
                        p *= 2
                    pts += p
                    exact_count += is_exact        # counts are NOT doubled
                    goal_diff_count += is_diff
            row[f"R{r}"] = pts
            total += pts

        row["Total"] = total
        row["Exact"] = exact_count
        row["Diff"] = goal_diff_count
        rows.append(row)

    df = pd.DataFrame(rows)
    if df.empty:
        df = pd.DataFrame(columns=["Player", "Total", "Exact", "Diff"])
        for r in present:
            df[f"R{r}"] = []
    df = df.sort_values(
        ["Total", "Exact", "Diff"],
        ascending=[False, False, False],
        kind="stable"
    ).reset_index(drop=True)
    df.insert(0, "#", range(1, len(df) + 1))
    return df


# ----------------------------------------------------------------------------
# Write paths (all re-validate against FRESH sheet data before writing)
# ----------------------------------------------------------------------------
def save_predictions(code, rnd, picks):
    """
    Append one authoritative row per match for a player's round predictions.

    picks = list of (match_id, pred_home, pred_away, zolik_bool); pred_home /
    pred_away may be None (not entered). This function is the security boundary:
    it re-reads fixtures, players and predictions FRESH (bypassing the cache),
    then enforces, in order and atomically (all-or-nothing):

      1. player still exists and is active,
      2. round still exists among valid fixtures,
      3. the round is NOT locked (deadline recomputed in Europe/Prague now),
      4. the submitted matches exactly match the round's current valid fixtures,
      5. every fixture has a complete, valid (int >= 0) home & away prediction,
      6. the player's resulting žolík total does not exceed their allowance.

    Raises PredictionError (safe, user-facing message) on any validation failure;
    Google-Sheets failures propagate as generic Exceptions to the caller, which
    must not surface secrets. No row is written unless every check passes.
    """
    code = norm_code(code)

    # --- fresh reads (never trust the cache at the save boundary) ---
    players_valid, _ = validate_players(read_records("Players", PLAYERS_HEADERS))
    fixtures_valid, _, _ = validate_fixtures(read_records("Fixtures", FIXTURES_HEADERS))
    predictions_fresh = read_records("Predictions", PREDICTIONS_HEADERS)

    # 1. player exists & active
    if not player_exists_active(players_valid, code):
        raise PredictionError("Tvůj hráčský kód není aktivní. Ověř ho u pořadatele.")

    # 2. round exists
    if rnd not in rounds_present(fixtures_valid):
        raise PredictionError(f"Kolo {rnd} už neexistuje. Obnov stránku a zkus to znovu.")

    # 3. deadline (recomputed now, Prague)
    dl = round_deadline(fixtures_valid, rnd)
    if dl is None:
        raise PredictionError(f"Kolo {rnd} nemá platné zápasy.")
    if now() >= dl:
        raise PredictionError(
            f"Kolo {rnd} je uzamčené — první zápas už začal ({dl.strftime('%a %d %b %H:%M')} "
            "Praha). Tipy nelze uložit."
        )

    # 4. submitted matches must match the round's current valid fixtures exactly
    valid_mids = {str(f["match_id"]) for f in round_fixtures(fixtures_valid, rnd)}
    submitted = {str(mid) for mid, _ph, _pa, _z in picks}
    if submitted != valid_mids:
        raise PredictionError(
            "Zápasy kola se změnily. Obnov stránku, tvůj formulář je neaktuální."
        )

    # 5. completeness & validity of every prediction (no partial saves)
    incomplete = []
    clean_picks = []
    for mid, ph, pa, z in picks:
        ih, ia = to_int(ph), to_int(pa)
        if ih is None or ia is None or ih < 0 or ia < 0:
            incomplete.append(str(mid))
            continue
        clean_picks.append((str(mid), ih, ia, bool(z)))
    if incomplete:
        raise PredictionError(
            f"Nevyplněné/neúplné tipy u {len(incomplete)} zápasů. "
            "Vyplň domácí i hosty u všech zápasů kola (0:0 je platný tip)."
        )

    # 6. žolík allowance (final total across all rounds after this save)
    granted = player_zoliky(players_valid, code)
    preds = latest_predictions(predictions_fresh)
    used_other = sum(1 for (c, r, _m), v in preds.items()
                     if c == code and r != rnd and v.get("zolik"))
    selected_this = sum(1 for _mid, _ph, _pa, z in clean_picks if z)
    final_total = used_other + selected_this
    if final_total > granted:
        over = final_total - granted
        raise PredictionError(
            f"Příliš mnoho žolíků. Máš {granted} celkem · {used_other} použ. v jiných kolech · "
            f"{selected_this} v tomto kole = {final_total} (o {over} přes limit). "
            "Odeber žolík. Další lze dokoupit po přijetí platby a navýšení limitu "
            "pořadatelem (pravidla 6.2 a 6.3)."
        )

    # --- all checks passed: append (append-only history, latest wins) ---
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Predictions", PREDICTIONS_HEADERS)
    ts = now().strftime("%Y-%m-%dT%H:%M:%S")
    rows = [[code, rnd, mid, ph, pa, ts, int(z)] for mid, ph, pa, z in clean_picks]
    ws.append_rows(rows, value_input_option="USER_ENTERED")
    refresh()


def save_registration(name, code, email):
    """Append a new registration request (status starts as 'čeká na platbu')."""
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Registrations", REGISTRATIONS_HEADERS)
    ts = now().strftime("%Y-%m-%dT%H:%M:%S")
    ws.append_rows([[name, norm_code(code), email, ts, "čeká na platbu"]],
                   value_input_option="USER_ENTERED")
    refresh()


def save_results(rnd, results_df):
    """
    Rewrite the Fixtures tab with updated real scores for `rnd`.

    Non-destructive to other rows. Blocks the write if the sheet contains
    duplicate match_ids (an unsafe critical-identifier state) so we never smear
    a result across ambiguous rows. Scores must be blank or integers >= 0.
    """
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Fixtures", FIXTURES_HEADERS)
    fixtures = ws.get_all_records()

    ids = [str(f.get("match_id", "")).strip() for f in fixtures]
    dups = {i for i in ids if i and ids.count(i) > 1}
    if dups:
        raise PredictionError(
            "V listu zápasů (Fixtures) jsou duplicitní identifikátory match_id: " + ", ".join(sorted(dups)) +
            ". Oprav je v tabulce, než zadáš výsledky."
        )

    edits = {str(r["match_id"]): r for _, r in results_df.iterrows()}
    body = []
    for f in fixtures:
        mid = str(f["match_id"])
        hs, as_ = f.get("home_score", ""), f.get("away_score", "")
        if mid in edits:
            eh, ea = edits[mid]["home_score"], edits[mid]["away_score"]
            hs = "" if pd.isna(eh) else int(eh)
            as_ = "" if pd.isna(ea) else int(ea)
        body.append([f["round"], f["match_id"], f["kickoff"], f["home"], f["away"], hs, as_])
    ws.update([FIXTURES_HEADERS] + body, value_input_option="USER_ENTERED")
    refresh()


def _player_edit_state(row):
    """Canonical editable values used for player-save conflict detection."""
    z = to_int(row.get("zoliky"))
    z = DEFAULT_ZOLIKY if z is None else max(0, min(z, MAX_ZOLIKY))
    return {
        "name": str(row.get("name", "")).strip(),
        "zoliky": z,
        "active": player_active(row),
    }


def save_player_names(edited_df, original_df):
    """
    Update only editable cells in existing Players rows.

    The previous implementation rebuilt the entire worksheet from the validated
    admin DataFrame. That could silently delete invalid rows excluded by
    validation, as well as rows added concurrently after the page was loaded.

    This version performs an optimistic, all-or-nothing targeted update:
      * codes identify existing rows but are never rewritten,
      * only name / zoliky / active cells are changed,
      * every row is re-read fresh immediately before the write,
      * the save is blocked if a row changed since the editor was loaded,
      * duplicate/missing codes block the save instead of updating ambiguously.
    """
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Players", PLAYERS_HEADERS)
    values = ws.get_all_values()  # fresh read at the write boundary
    if not values:
        raise PredictionError("List hráčů (Players) je prázdný nebo nemá hlavičku.")

    header = [str(v).strip() for v in values[0]]
    missing_headers = [h for h in PLAYERS_HEADERS if h not in header]
    if missing_headers:
        raise PredictionError(
            "V listu hráčů (Players) chybí sloupce: " + ", ".join(missing_headers) + "."
        )

    col = {name: header.index(name) + 1 for name in PLAYERS_HEADERS}  # 1-based

    # Keep every physical sheet row, including invalid rows. Player codes are
    # mapped to sheet rows only for unambiguous targeted updates.
    rows_by_code = {}
    row_records = {}
    for sheet_row, raw in enumerate(values[1:], start=2):
        record = {
            name: (raw[col[name] - 1] if len(raw) >= col[name] else "")
            for name in PLAYERS_HEADERS
        }
        code = norm_code(record.get("code", ""))
        if not code:
            continue
        rows_by_code.setdefault(code, []).append(sheet_row)
        row_records[sheet_row] = record

    original_by_code = {
        norm_code(r.get("code", "")): _player_edit_state(r)
        for _, r in original_df.iterrows()
        if norm_code(r.get("code", ""))
    }

    pending = []
    conflicts = []

    for _, edited in edited_df.iterrows():
        code = norm_code(edited.get("code", ""))
        if not code or code not in original_by_code:
            conflicts.append(f"neznámý kód '{code or '—'}'")
            continue

        matching_rows = rows_by_code.get(code, [])
        if not matching_rows:
            conflicts.append(f"{code}: řádek byl mezitím odstraněn")
            continue
        if len(matching_rows) > 1:
            conflicts.append(f"{code}: duplicitní kód v listu Players")
            continue

        sheet_row = matching_rows[0]
        current = _player_edit_state(row_records[sheet_row])
        original = original_by_code[code]
        if current != original:
            conflicts.append(f"{code}: údaje se od otevření editoru změnily")
            continue

        desired = _player_edit_state(edited)
        active_value = "yes" if desired["active"] else "no"
        desired_cells = {
            "name": desired["name"],
            "zoliky": desired["zoliky"],
            "active": active_value,
        }
        current_cells = {
            "name": current["name"],
            "zoliky": current["zoliky"],
            "active": "yes" if current["active"] else "no",
        }

        for field in ("name", "zoliky", "active"):
            if desired_cells[field] != current_cells[field]:
                pending.append(
                    Cell(sheet_row, col[field], desired_cells[field])
                )

    if conflicts:
        raise PredictionError(
            "Hráče se nepodařilo uložit bezpečně: " + "; ".join(conflicts) +
            ". Obnov stránku a zkus změny znovu. Nic nebylo zapsáno."
        )

    if pending:
        ws.update_cells(pending, value_input_option="USER_ENTERED")
        refresh()
    return len(pending)


def add_player(code, name, zoliky=DEFAULT_ZOLIKY, active=True):
    """Append a single player (used when approving a registration). Skips dup codes."""
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Players", PLAYERS_HEADERS)
    code = norm_code(code)
    existing = {norm_code(p["code"]) for p in ws.get_all_records()}
    if code in existing:
        return False
    z = max(0, min(to_int(zoliky) if to_int(zoliky) is not None else DEFAULT_ZOLIKY, MAX_ZOLIKY))
    ws.append_rows([[code, str(name).strip(), z, "yes" if active else "no"]],
                   value_input_option="USER_ENTERED")
    refresh()
    return True


def add_round_fixtures(rnd, fixtures_df):
    """Append fixtures for a round. Skips blank rows; keeps match_id numbering unique."""
    sh = get_spreadsheet()
    ws = ensure_ws(sh, "Fixtures", FIXTURES_HEADERS)
    existing = ws.get_all_records()
    n = len([f for f in existing if to_int(f["round"]) == rnd])
    rows = []
    for i, (_, r) in enumerate(fixtures_df.iterrows(), start=n + 1):
        if not str(r["home"]).strip() or not str(r["away"]).strip():
            continue
        rows.append([rnd, f"R{rnd}M{i}", str(r["kickoff"]), str(r["home"]), str(r["away"]), "", ""])
    if rows:
        ws.append_rows(rows, value_input_option="USER_ENTERED")
        refresh()
    return len(rows)


