def countdown_component(deadline, rnd, fixtures):
    """Broadcast-style live countdown to the round deadline (signature element)."""
    target_iso = deadline.isoformat()
    dl_label = format_datetime_cz(deadline)
    fixtures_now = round_fixtures(fixtures, rnd)
    fixture_cards = "".join(_fixture_card_html(f) for f in fixtures_now)
    html_block = f"""
    <div id="cd-wrap">
      <style>
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800&display=swap');
        #cd-wrap {{ font-family:'Outfit',sans-serif; }}
        .board {{
          background:{INK};
          border:1px solid #3a1140;
          border-radius:18px;
          padding:18px 18px 16px;
          color:#fff;
          box-shadow:0 10px 28px rgba(18,0,28,.22);
        }}
        .cap {{
          text-transform:uppercase;
          letter-spacing:2px;
          font-size:.8rem;
          font-weight:700;
          color:{CYAN};
          margin-bottom:10px;
        }}
        .clock {{ display:flex; gap:12px; margin:0 0 6px; flex-wrap:wrap; }}
        .unit {{
          background:#2a0730;
          border-radius:12px;
          padding:10px 0 9px;
          width:80px;
          text-align:center;
          border:1px solid #491450;
        }}
        .num {{ font-weight:800; font-size:2.35rem; line-height:1; color:#fff; }}
        .lab {{ font-size:.60rem; text-transform:uppercase; letter-spacing:1.5px; color:#c79ccf; margin-top:6px; }}
        .dl {{ color:#e9c9ee; font-size:.9rem; margin-top:4px; font-weight:600; }}
        .live {{ color:{PINK}; font-size:1.25rem; letter-spacing:1px; font-weight:800; }}
        .fixtures {{ margin-top:14px; padding-top:4px; display:grid; gap:8px; }}
        .fixture-card {{
          display:grid;
          grid-template-columns:minmax(0,1fr) 100px minmax(0,1fr);
          align-items:center;
          gap:12px;
          background:rgba(255,255,255,.025);
          border-radius:14px;
          padding:9px 14px;
        }}
        .team-side {{ display:flex; align-items:center; gap:10px; min-width:0; }}
        .team-home {{ justify-content:flex-end; }}
        .team-away {{ justify-content:flex-start; }}
        .team-name {{
          font-size:.95rem;
          font-weight:700;
          color:#FFFFFF;
          white-space:nowrap;
          overflow:hidden;
          text-overflow:ellipsis;
        }}
        .home-name {{ text-align:right; }}
        .away-name {{ text-align:left; }}
        .team-logo-wrap {{
          width:32px;
          height:32px;
          display:flex;
          align-items:center;
          justify-content:center;
          flex:0 0 auto;
        }}
        .team-logo {{
          width:32px;
          height:32px;
          object-fit:contain;
          display:block;
          filter: drop-shadow(0 1px 2px rgba(0,0,0,.18));
        }}
        .team-badge {{
          width:32px;
          height:32px;
          border-radius:999px;
          display:flex;
          align-items:center;
          justify-content:center;
          font-size:.62rem;
          font-weight:800;
          letter-spacing:.04em;
          border:2px solid rgba(255,255,255,.14);
          box-shadow: inset 0 0 0 1px rgba(0,0,0,.08);
          flex:0 0 auto;
        }}
        .fixture-mid {{ text-align:center; }}
        .fixture-date {{ color:#C6A6D7; font-size:.66rem; font-weight:700; text-transform:uppercase; letter-spacing:.05em; line-height:1.1; }}
        .fixture-time {{ color:{CYAN}; font-size:1rem; font-weight:800; line-height:1.12; margin-top:3px; }}
        @media (max-width: 760px) {{
          .unit {{ width:64px; padding:8px 0 7px; }}
          .num {{ font-size:1.7rem; }}
          .fixture-card {{ grid-template-columns:minmax(0,1fr) 72px minmax(0,1fr); gap:8px; padding:8px 10px; }}
          .team-name {{ font-size:.78rem; }}
          .team-logo-wrap, .team-logo {{ width:24px; height:24px; }}
          .team-badge {{ width:24px; height:24px; font-size:.5rem; }}
          .fixture-date {{ font-size:.58rem; }}
          .fixture-time {{ font-size:.85rem; }}
        }}
      </style>
      <div class="board">
        <div class="cap">Kolo {rnd} · tipy se uzamknou za</div>
        <div class="clock" id="clock">
          <div class="unit"><div class="num" id="d">--</div><div class="lab">dní</div></div>
          <div class="unit"><div class="num" id="h">--</div><div class="lab">hod</div></div>
          <div class="unit"><div class="num" id="m">--</div><div class="lab">min</div></div>
          <div class="unit"><div class="num" id="s">--</div><div class="lab">sek</div></div>
        </div>
        <div class="dl">Uzamčení: {dl_label} — výkop prvního zápasu kola</div>
        <div class="fixtures">{fixture_cards}</div>
      </div>
    </div>
    <script>
      const target = new Date("{target_iso}").getTime();
      const clock = document.getElementById("clock");
      function pad(n) {{ return String(n).padStart(2,"0"); }}
      function tick() {{
        const diff = target - Date.now();
        if (diff <= 0) {{
          clock.innerHTML = '<div class="live">TIPY UZAMČENY — HODNĚ ŠTĚSTÍ</div>';
          return;
        }}
        const d = Math.floor(diff/86400000);
        const h = Math.floor(diff%86400000/3600000);
        const m = Math.floor(diff%3600000/60000);
        const s = Math.floor(diff%60000/1000);
        document.getElementById("d").textContent = d;
        document.getElementById("h").textContent = pad(h);
        document.getElementById("m").textContent = pad(m);
        document.getElementById("s").textContent = pad(s);
      }}
      tick(); setInterval(tick, 1000);
    </script>
    """
    components.html(html_block, height=210 + 58 * len(fixtures_now))


def _team_style(team):
    meta = TEAM_STYLE.get(str(team), {})
    words = str(team).replace("Manchester ", "M ").split()
    fallback = "".join(w[:1] for w in words)[:3].upper() or "FC"
    return {
        "abbr": meta.get("abbr", fallback),
        "bg": meta.get("bg", "#FFFFFF"),
        "fg": meta.get("fg", INK),
    }


def _team_logo_data_uri(team):
    base = TEAM_LOGO_FILES.get(str(team))
    if not base:
        return None
    logo_dir = Path(__file__).resolve().parent / "team_logos"
    for ext, mime in (("svg", "image/svg+xml"), ("png", "image/png"), ("webp", "image/webp"), ("jpg", "image/jpeg"), ("jpeg", "image/jpeg")):
        p = logo_dir / f"{base}.{ext}"
        if p.exists():
            return f"data:{mime};base64," + base64.b64encode(p.read_bytes()).decode("ascii")
    return None


def _team_mark_html(team, side_class):
    safe_name = html.escape(str(team))
    logo_uri = _team_logo_data_uri(team)
    if logo_uri:
        logo_html = (
            f"<div class='team-logo-wrap'><img class='team-logo' src='{logo_uri}' alt='{safe_name} logo'></div>"
        )
    else:
        meta = _team_style(team)
        logo_html = (
            f"<div class='team-badge' style='background:{meta['bg']};color:{meta['fg']};border-color:{meta['fg']}22;'>{meta['abbr']}</div>"
        )
    if side_class == "team-home":
        return f"<div class='team-side {side_class}'><div class='team-name home-name'>{safe_name}</div>{logo_html}</div>"
    return f"<div class='team-side {side_class}'>{logo_html}<div class='team-name away-name'>{safe_name}</div></div>"


def _fixture_card_html(fixture):
    ko = parse_kickoff(fixture["kickoff"])
    weekday = ["po", "út", "st", "čt", "pá", "so", "ne"][ko.weekday()]
    date_label = f"{weekday} {ko.strftime('%d.%m.')}"
    time_label = ko.strftime("%H:%M")
    home_html = _team_mark_html(fixture["home"], "team-home")
    away_html = _team_mark_html(fixture["away"], "team-away")
    return f"""
      <div class="fixture-card">
        {home_html}
        <div class="fixture-mid">
          <div class="fixture-date">{date_label}</div>
          <div class="fixture-time">{time_label}</div>
        </div>
        {away_html}
      </div>
    """

def data_issue_note(rounds_with_issues, rnd):
    """Simple player-facing warning if the current round has invalid fixture data."""
    if rnd in rounds_with_issues:
        st.warning("⚠️ V tomto kole jsou nějaké chybné údaje o zápasech. "
                   "Zobrazují se jen platné zápasy — pořadatel byl upozorněn.")


def render_leaderboard(players, fixtures, predictions):
    df = compute_leaderboard(players, fixtures, predictions)
    present = rounds_present(fixtures)
    head = "".join(f"<th>R{r}</th>" for r in present)
    body = ""
    for i, r in df.iterrows():
        cls = "top" if i < 3 else ""
        safe_player = html.escape(str(r["Player"]))
        cells = "".join(f"<td>{int(r[f'R{n}'])}</td>" for n in present)
        body += (
            f"<tr class='{cls}'><td class='rank'>{r['#']}</td>"
            f"<td class='player'>{safe_player}</td>"
            f"<td class='total'>{int(r['Total'])}</td>{cells}"
            f"<td class='stat'>{int(r['Exact'])}</td>"
            f"<td class='stat'>{int(r['Diff'])}</td></tr>"
        )
    if not body:
        body = ("<tr><td class='player' colspan='%d' "
                "style='text-align:center;color:#999;padding:16px'>"
                "Zatím žádní aktivní hráči.</td></tr>" % (len(present) + 5))
    st.markdown(
        f"<div class='leaderboard-card'><table class='lb'>"
        f"<thead><tr><th>#</th><th class='player'>Hráč</th>"
        f"<th>Celkem</th>{head}<th title='Přesná skóre'>Přesně</th>"
        f"<th title='Správné rozdíly skóre'>Rozdíl</th></tr></thead>"
        f"<tbody>{body}</tbody></table></div>",
        unsafe_allow_html=True,
    )
    st.caption(
        "**Rozhodování shod:** Celkové body → přesná skóre → správné rozdíly skóre. "
        "Pokud shoda trvá, rozhodne los."
    )
    if not any(is_locked(fixtures, r) for r in present):
        st.caption("Zatím nebylo uzamčeno žádné kolo — body se zobrazí po uzamčení kola a zadání výsledků.")


def predictions_panel(players, fixtures, predictions, rounds_with_issues):
    st.subheader("Zadej své tipy")

    # Fixed confirmation remains visible even when Streamlit restores the user's
    # scroll position near the bottom of this long form after a successful save.
    if st.session_state.pop("pred_saved", False):
        st.markdown(
            """
            <div class="prediction-save-toast" role="status" aria-live="polite">
              <div class="prediction-save-toast-title">Tipy byly uloženy</div>
              <div class="prediction-save-toast-copy">Do uzamčení kola je můžeš kdykoli upravit.</div>
            </div>
            <style>
              .prediction-save-toast {
                position: fixed;
                right: 24px;
                bottom: 24px;
                z-index: 999999;
                min-width: 280px;
                max-width: min(390px, calc(100vw - 32px));
                padding: .82rem 1rem;
                background: #FFFFFF;
                color: #1A0022;
                border: 1px solid #D8ECDD;
                border-left: 5px solid #00C853;
                border-radius: 13px;
                box-shadow: 0 14px 38px rgba(26, 0, 34, .22);
                animation: predictionToastOut .35s ease 6s forwards;
              }
              .prediction-save-toast-title {
                font-size: .95rem;
                font-weight: 800;
                line-height: 1.2;
              }
              .prediction-save-toast-copy {
                margin-top: .16rem;
                color: #65556B;
                font-size: .82rem;
                line-height: 1.35;
              }
              @keyframes predictionToastOut {
                to { opacity: 0; transform: translateY(10px); pointer-events: none; }
              }
              @media (max-width: 640px) {
                .prediction-save-toast {
                  left: 16px;
                  right: 16px;
                  bottom: 16px;
                  min-width: 0;
                }
              }
            </style>
            """,
            unsafe_allow_html=True,
        )

    codes = {norm_code(p["code"]) for p in active_players(players)}
    raw_code = st.text_input("Tvůj hráčský kód", key="pred_code",
                             placeholder="např. JANN").strip()
    if not raw_code:
        st.info("Zadej svůj kód a načtou se zápasy k natipování.")
        return
    code = norm_code(raw_code)
    if code not in codes:
        st.error("Tento kód nebyl rozpoznán nebo není aktivní. Ověř ho u organizátora.")
        return

    st.success(f"Vítej, {player_name(players, code)}!")
    save_state_slot = st.empty()
    st.markdown(
        """
        <style>
          .prediction-save-state {
            display:inline-flex;
            align-items:center;
            gap:.22rem;
            margin:-.2rem 0 .45rem;
            padding:.42rem .68rem;
            border-radius:10px;
            font-size:.84rem;
            line-height:1.25;
            border:1px solid transparent;
          }
          .prediction-save-state.saved {
            color:#137A46;
            background:#EAF8F0;
            border-color:#CDEEDB;
          }
          .prediction-save-state.draft {
            color:#8A4B08;
            background:#FFF5E6;
            border-color:#F4D7A7;
          }
          .prediction-save-state.empty {
            color:#65556B;
            background:#F7F3F8;
            border-color:#E9E0EC;
          }
        </style>
        """,
        unsafe_allow_html=True,
    )
    present = rounds_present(fixtures) or [1]
    default = active_round(fixtures)
    rnd = st.selectbox("Kolo", present, index=present.index(default) if default in present else 0)
    preds = latest_predictions(predictions)

    data_issue_note(rounds_with_issues, rnd)

    fs = round_fixtures(fixtures, rnd)
    saved_round_rows = [
        preds.get((code, rnd, str(f["match_id"])))
        for f in fs
    ]
    saved_timestamps = [
        row.get("updated_at") for row in saved_round_rows
        if row and row.get("updated_at")
    ]
    last_saved_raw = max(saved_timestamps) if saved_timestamps else None
    last_saved_label = format_saved_at_cz(last_saved_raw) if last_saved_raw else None

    if is_locked(fixtures, rnd):
        if last_saved_label:
            save_state_slot.markdown(
                f"<div class='prediction-save-state saved'><b>Uloženo</b> · naposledy uloženo {last_saved_label} · kolo {rnd}</div>",
                unsafe_allow_html=True,
            )
        else:
            save_state_slot.markdown(
                f"<div class='prediction-save-state empty'><b>Bez uložených tipů</b> · kolo {rnd}</div>",
                unsafe_allow_html=True,
            )
        st.markdown("<span class='pill locked'>🔒 Uzamčeno</span>", unsafe_allow_html=True)
        st.warning(f"Kolo {rnd} je uzamčeno — první zápas už začal. Tipy najdeš v záložce Výsledky.")
        return

    if not fs:
        save_state_slot.markdown(
            f"<div class='prediction-save-state empty'><b>Bez uložených tipů</b> · kolo {rnd}</div>",
            unsafe_allow_html=True,
        )
        st.warning("Tohle kolo nemá žádné platné zápasy.")
        return

    dl = round_deadline(fixtures, rnd)
    st.markdown(
        f"<span class='pill open'>OTEVŘENO</span> &nbsp; Uzamčení: **{format_datetime_cz(dl)}**",
        unsafe_allow_html=True,
    )
    granted = player_zoliky(players, code)
    # jokers already committed on OTHER rounds (this round's are read live from the checkboxes)
    used_other = sum(1 for (c, r, _m), v in preds.items()
                     if c == code and r != rnd and v.get("zolik"))

    # Scope every prediction widget to the active player and round. Streamlit
    # preserves keyed widget state for the browser session; match-only keys would
    # otherwise leak one player's in-progress values when another code is entered.
    def pred_key(field, match_id):
        return f"pred_{field}_{code}_{rnd}_{match_id}"

    # Live count of this round's ticks from scoped widget state. When a widget has
    # not rendered yet, fall back to that player's persisted žolík value.
    ticked_now = sum(
        1
        for f in fs
        if st.session_state.get(
            pred_key("z", f["match_id"]),
            bool(preds.get((code, rnd, str(f["match_id"])), {}).get("zolik", False)),
        )
    )
    remaining_now = granted - used_other - ticked_now
    remaining_class = "joker-count-alert" if remaining_now < 0 else "joker-count-ok"
    st.markdown(
        f"""
        <div class="prediction-joker-help">
          <div class="prediction-joker-copy">
            <b>Žolíky:</b> použitý žolík <b>zdvojnásobí</b> body za vybraný zápas.
            U zvoleného zápasu zaškrtni <b>Ž&nbsp;2×</b>.
          </div>
          <div class="prediction-joker-count {remaining_class}">
            <span>Zbývající žolíky</span>
            <strong>{remaining_now} z {granted}</strong>
          </div>
        </div>
        <style>
          .prediction-joker-help {{
            display:flex;
            align-items:center;
            justify-content:space-between;
            gap:18px;
            margin:.55rem 0 .85rem;
            padding:.75rem .9rem;
            background:#FAF8FC;
            border:1px solid #EEE7F1;
            border-radius:12px;
          }}
          .prediction-joker-copy {{
            color:#2B1830;
            font-size:.94rem;
            line-height:1.4;
          }}
          .prediction-joker-count {{
            display:flex;
            align-items:baseline;
            gap:8px;
            white-space:nowrap;
            padding:.42rem .68rem;
            border-radius:10px;
          }}
          .prediction-joker-count span {{
            font-size:.72rem;
            font-weight:700;
            text-transform:uppercase;
            letter-spacing:.05em;
          }}
          .prediction-joker-count strong {{
            font-size:1.05rem;
            font-weight:800;
          }}
          .joker-count-ok {{ background:#EAF8F0; color:#137A46; }}
          .joker-count-alert {{ background:#FDECEF; color:#B4233C; }}
          @media (max-width:700px) {{
            .prediction-joker-help {{ align-items:flex-start; flex-direction:column; gap:10px; }}
          }}
        </style>
        """,
        unsafe_allow_html=True,
    )

    # Keep every match visually bound to its own joker checkbox. Alternating
    # row cards make it much harder to accidentally tick a joker on the wrong game.
    st.markdown(
        """
        <style>
          [class*="st-key-pred-match-row-"] {
            border-radius: 12px;
            padding: .42rem .72rem .20rem;
            margin-bottom: .34rem;
            border: 1px solid transparent;
          }
          [class*="st-key-pred-match-row-even-"] {
            background: #FAF8FC;
            border-color: #F0EAF3;
          }
          [class*="st-key-pred-match-row-odd-"] {
            background: #FFFFFF;
            border-color: #F5F1F7;
          }
          [class*="st-key-pred-match-row-"] [data-testid="stHorizontalBlock"] {
            align-items: center;
          }
          [class*="st-key-pred-match-row-"] [data-testid="stCheckbox"] {
            margin-top: 0;
          }
          .prediction-team {
            display:flex;
            align-items:center;
            gap:9px;
            min-height:34px;
            padding-top:1px;
            min-width:0;
          }
          .prediction-team-home { justify-content:flex-end; }
          .prediction-team-away { justify-content:flex-start; }
          .prediction-team-name {
            color:#1A0022;
            font-size:.95rem;
            font-weight:700;
            line-height:1.2;
            white-space:nowrap;
            overflow:hidden;
            text-overflow:ellipsis;
          }
          .prediction-team-home .prediction-team-name { text-align:right; }
          .prediction-team-logo-wrap {
            width:30px;
            height:30px;
            display:flex;
            align-items:center;
            justify-content:center;
            flex:0 0 auto;
          }
          .prediction-team-logo {
            width:29px;
            height:29px;
            object-fit:contain;
            display:block;
          }
          .prediction-team-badge {
            width:28px;
            height:28px;
            border-radius:999px;
            display:flex;
            align-items:center;
            justify-content:center;
            flex:0 0 auto;
            font-size:.56rem;
            font-weight:800;
            letter-spacing:.03em;
            border:1px solid rgba(26,0,34,.10);
          }
          /* Kickoff label centered above each match */
          .pred-kickoff {
            text-align:center;
            font-size:.68rem;
            font-weight:700;
            letter-spacing:.06em;
            text-transform:uppercase;
            color:#8A769B;
            margin:1px 0 0;
          }
          /* Score boxes: no +/- steppers, compact square, centered digits */
          [class*="st-key-pred-match-row-"] button[data-testid="stNumberInputStepDown"],
          [class*="st-key-pred-match-row-"] button[data-testid="stNumberInputStepUp"],
          [class*="st-key-pred-match-row-"] [data-testid^="stNumberInputStep"] {
            display:none !important;
          }
          [class*="st-key-pred-match-row-"] [data-testid="stNumberInput"] div[data-baseweb="input"] {
            max-width:54px;
            margin:0 auto;
            border-radius:10px;
          }
          [class*="st-key-pred-match-row-"] [data-testid="stNumberInput"] input {
            text-align:center;
            font-weight:700;
            padding:.42rem .1rem;
          }
          /* Phones: reflow each card to [teams+logos] over [score : score | Ž 2×] */
          @media (max-width:640px) {
            [class*="st-key-pred-match-row-"] {
              padding:.55rem .55rem .3rem;
              margin-bottom:.5rem;
            }
            /* Streamlit collapses the team-name columns to ~10px; reserve the
               real line height so the score row can't overlap the names. */
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(1),
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(5) {
              min-height:30px !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stHorizontalBlock"] {
              flex-wrap:wrap !important;
              row-gap:2px;
              column-gap:.45rem;
              align-items:center;
              justify-content:center;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"],
            [class*="st-key-pred-match-row-"] [data-testid="column"] {
              min-width:0 !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(1) {
              order:1; width:auto !important; flex:1 1 42% !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(5) {
              order:2; width:auto !important; flex:1 1 42% !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(2) {
              order:3; width:auto !important; flex:0 1 80px !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(3) {
              order:4; width:auto !important; flex:0 0 8px !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(4) {
              order:5; width:auto !important; flex:0 1 80px !important;
            }
            [class*="st-key-pred-match-row-"] [data-testid="stColumn"]:nth-child(6) {
              order:6; width:auto !important; flex:0 0 auto !important;
            }
            .prediction-team { min-height:26px; }
            .prediction-team-name { font-size:.85rem; }
            .prediction-team-logo-wrap, .prediction-team-logo { width:24px; height:24px; }
            .prediction-team-badge { width:23px; height:23px; font-size:.5rem; }
          }
        </style>
        """,
        unsafe_allow_html=True,
    )

    picks = []
    for row_i, f in enumerate(fs):
        mid = str(f["match_id"])
        prev = preds.get((code, rnd, mid))
        # None => never entered (empty box); an entered 0 stays 0
        ph0 = prev["pred_home"] if prev else None
        pa0 = prev["pred_away"] if prev else None
        z0 = bool(prev["zolik"]) if prev else False

        safe_home = html.escape(str(f["home"]))
        safe_away = html.escape(str(f["away"]))
        home_logo_uri = _team_logo_data_uri(f["home"])
        away_logo_uri = _team_logo_data_uri(f["away"])
        home_meta = _team_style(f["home"])
        away_meta = _team_style(f["away"])
        home_mark = (
            f"<span class='prediction-team-logo-wrap'><img class='prediction-team-logo' "
            f"src='{home_logo_uri}' alt=''></span>"
            if home_logo_uri
            else f"<span class='prediction-team-badge' style='background:{home_meta['bg']};"
                 f"color:{home_meta['fg']}'>{home_meta['abbr']}</span>"
        )
        away_mark = (
            f"<span class='prediction-team-logo-wrap'><img class='prediction-team-logo' "
            f"src='{away_logo_uri}' alt=''></span>"
            if away_logo_uri
            else f"<span class='prediction-team-badge' style='background:{away_meta['bg']};"
                 f"color:{away_meta['fg']}'>{away_meta['abbr']}</span>"
        )
        stripe = "even" if row_i % 2 == 0 else "odd"
        row_key = f"pred-match-row-{stripe}-{code}-{rnd}-{mid}"

        ko_label = format_datetime_cz(parse_kickoff(f["kickoff"]))
        with st.container(key=row_key):
            st.markdown(f"<div class='pred-kickoff'>{ko_label}</div>", unsafe_allow_html=True)
            c1, c2, c3, c4, c5, c6 = st.columns([2.45, .85, .22, .85, 2.45, 1.05])
            c1.markdown(
                f"<div class='prediction-team prediction-team-home'>"
                f"<span class='prediction-team-name'>{safe_home}</span>{home_mark}</div>",
                unsafe_allow_html=True,
            )
            ph = c2.number_input(
                "h", min_value=0, max_value=20,
                value=(int(ph0) if ph0 is not None else None),
                step=1, key=pred_key("home", mid), label_visibility="collapsed",
                placeholder="–",
            )
            c3.markdown(
                "<div style='text-align:center;padding-top:6px;color:#999'>:</div>",
                unsafe_allow_html=True,
            )
            pa = c4.number_input(
                "a", min_value=0, max_value=20,
                value=(int(pa0) if pa0 is not None else None),
                step=1, key=pred_key("away", mid), label_visibility="collapsed",
                placeholder="–",
            )
            c5.markdown(
                f"<div class='prediction-team prediction-team-away'>{away_mark}"
                f"<span class='prediction-team-name'>{safe_away}</span></div>",
                unsafe_allow_html=True,
            )

            z_key = pred_key("z", mid)
            cur_z = st.session_state.get(z_key, z0)
            # UI-level žolík guard: block ticking a NEW box once the allowance is spent.
            disable_z = (not cur_z) and (used_other + ticked_now >= granted)
            z = c6.checkbox(
                "Ž 2×", value=z0, key=z_key, disabled=disable_z,
            )
        picks.append((mid, ph, pa, z))

    # Saved-vs-draft status is rendered in the placeholder directly below the
    # welcome message. Streamlit reruns on every edit, so this stays live.
    has_saved_round = any(row is not None for row in saved_round_rows)
    draft_changed = False
    any_draft_value = False
    for mid, ph, pa, z in picks:
        saved = preds.get((code, rnd, str(mid)))
        saved_home = saved.get("pred_home") if saved else None
        saved_away = saved.get("pred_away") if saved else None
        saved_zolik = bool(saved.get("zolik", False)) if saved else False
        current_home = to_int(ph)
        current_away = to_int(pa)
        current_zolik = bool(z)
        any_draft_value = any_draft_value or (
            current_home is not None or current_away is not None or current_zolik
        )
        if (current_home, current_away, current_zolik) != (
            saved_home, saved_away, saved_zolik
        ):
            draft_changed = True

    if has_saved_round and draft_changed:
        saved_suffix = f" · poslední uložená verze: {last_saved_label}" if last_saved_label else ""
        save_state_slot.markdown(
            f"<div class='prediction-save-state draft'><b>Neuložené změny</b>{saved_suffix} · kolo {rnd}</div>",
            unsafe_allow_html=True,
        )
    elif has_saved_round:
        saved_suffix = f" · naposledy uloženo: {last_saved_label}" if last_saved_label else ""
        save_state_slot.markdown(
            f"<div class='prediction-save-state saved'><b>Uloženo</b>{saved_suffix} · kolo {rnd}</div>",
            unsafe_allow_html=True,
        )
    elif any_draft_value:
        save_state_slot.markdown(
            f"<div class='prediction-save-state draft'><b>Neuložený rozepsaný tip</b> · kolo {rnd}</div>",
            unsafe_allow_html=True,
        )
    else:
        save_state_slot.markdown(
            f"<div class='prediction-save-state empty'><b>Zatím neuloženo</b> · kolo {rnd}</div>",
            unsafe_allow_html=True,
        )

    # --- completeness ---
    total_fx = len(picks)
    complete = [(mid, ph, pa, z) for mid, ph, pa, z in picks
                if ph is not None and pa is not None]
    incomplete = [mid for mid, ph, pa, z in picks
                  if (ph is None) != (pa is None) or (ph is None and pa is None)]
    n_done = len(complete)
    st.caption(f"**Vyplněno {n_done} z {total_fx} tipů.**")
    if incomplete:
        names = {str(f["match_id"]): f"{f['home']}–{f['away']}" for f in fs}
        st.info("Chybí doplnit: " + ", ".join(names[m] for m in incomplete) +
                " — zadej skóre domácích i hostů (0 je platný tip).")

    # --- žolík summary ---
    used_this_round = sum(1 for _, _, _, z in picks if z)
    total_used = used_other + used_this_round
    remaining = granted - total_used
    if remaining < 0:
        st.error(f"Označil(a) jsi {total_used} žolíků, ale k dispozici máš jen {granted} "
                 f"({used_this_round} zde + {used_other} v ostatních kolech). Před uložením některé odeber.")

    can_save = (n_done == total_fx) and (remaining >= 0)
    if st.button("Uložit moje tipy", type="primary", disabled=not can_save):
        try:
            save_predictions(code, rnd, picks)
        except PredictionError as e:
            st.error(str(e))
        except Exception:  # noqa: BLE001 — Google Sheets / network failure
            st.error("Nepodařilo se uložit do tabulky (spojení / Google Sheets). "
                     "Zkus to prosím znovu za chvíli.")
        else:
            st.session_state["pred_saved"] = True
            st.rerun()
    if not can_save:
        st.caption("Uložení bude dostupné až po vyplnění všech zápasů a dodržení limitu žolíků.")


def results_panel(players, fixtures, predictions, rounds_with_issues):
    st.subheader("Výsledky a tipy hráčů")
    players = active_players(players)
    zmap = canonical_zolik_map(players, predictions)
    present = rounds_present(fixtures)
    locked = [r for r in present if is_locked(fixtures, r)]
    if not locked:
        st.info("Zatím není co zobrazit — tipy hráčů se odkryjí po uzamčení kola.")
        return

    rnd = st.selectbox("Kolo", locked, index=len(locked) - 1, key="res_round")
    data_issue_note(rounds_with_issues, rnd)
    preds = latest_predictions(predictions)

    for f in round_fixtures(fixtures, rnd):
        mid = str(f["match_id"])
        ah, aa = f.get("home_score"), f.get("away_score")
        real = f"{ah}–{aa}" if ah is not None and aa is not None else "— : —"
        title = html.escape(f"{f['home']} {real} {f['away']}")

        body_rows = []
        has_counted_joker = False
        for pl in players:
            code = norm_code(pl["code"])
            pr = preds.get((code, rnd, mid))
            counted = (rnd, mid) in zmap.get(code, {}).get("counted", set())
            row_class = "joker" if counted else ""
            has_counted_joker = has_counted_joker or counted

            player_name_safe = html.escape(str(pl["name"]))
            if not pr or pr["pred_home"] is None or pr["pred_away"] is None:
                body_rows.append(
                    f"<tr class='{row_class}'><td class='player-name'>{player_name_safe}</td>"
                    "<td class='pick-cell empty-cell'>—</td>"
                    "<td class='pts-cell empty-cell'>—</td></tr>"
                )
                continue

            pick = html.escape(f"{pr['pred_home']}–{pr['pred_away']}")
            pts = "—"
            if ah is not None and aa is not None:
                p, _is_exact, _is_diff, _is_winner = score_prediction_detailed(
                    pr["pred_home"], pr["pred_away"], ah, aa
                )
                if counted:
                    p *= 2
                pts = str(p)

            body_rows.append(
                f"<tr class='{row_class}'><td class='player-name'>{player_name_safe}</td>"
                f"<td class='pick-cell'>{pick}</td>"
                f"<td class='pts-cell'>{pts}</td></tr>"
            )

        table_html = (
            f"<div class='result-card'><div class='result-head'>{title}</div>"
            "<table class='result-table'>"
            "<thead><tr><th>Hráč</th><th>Tip</th><th>Body</th></tr></thead>"
            f"<tbody>{''.join(body_rows)}</tbody></table></div>"
        )
        st.markdown(table_html, unsafe_allow_html=True)
        if has_counted_joker:
            st.markdown(
                "<div class='result-note'>Růžový řádek označuje platně použitý žolík (2× body).</div>",
                unsafe_allow_html=True,
            )

def organiser_diagnostics(fix_problems, ply_problems, players, predictions):
    """Detailed organiser-only data-quality report (row numbers + specifics)."""
    excess = zolik_excess_report(players, predictions)
    n = len(fix_problems) + len(ply_problems) + len(excess)
    with st.expander(f"⚠️ Kontrola dat ({n})", expanded=bool(n)):
        if not n:
            st.success("Žádné problémy v datech. ✅")
            return
        if fix_problems:
            st.markdown("**Zápasy — problémové řádky:**")
            st.dataframe(pd.DataFrame(fix_problems, columns=["Řádek", "Problém"]),
                         hide_index=True, use_container_width=True)
        if ply_problems:
            st.markdown("**Hráči — problémové řádky:**")
            st.dataframe(pd.DataFrame(ply_problems, columns=["Řádek", "Problém"]),
                         hide_index=True, use_container_width=True)
        if excess:
            st.markdown("**Žolíky nad limit** (započítají se jen nejdříve použité žolíky do přiděleného limitu; "
                        "zbytek se při bodování ignoruje):")
            st.dataframe(
                pd.DataFrame(excess, columns=["Kód", "Jméno", "Přiděleno", "Použito", "Přes limit"]),
                hide_index=True, use_container_width=True)


def admin_panel(players, fixtures, predictions, fix_problems, ply_problems):
    st.subheader("Nástroje organizátora")
    st.caption("Zadávej skutečné výsledky, spravuj kola, hráče a registrace.")

    organiser_diagnostics(fix_problems, ply_problems, players, predictions)

    tab_res, tab_fix, tab_ply, tab_reg = st.tabs(
        ["Zadat výsledky", "Přidat kolo", "Hráči", "Registrace"]
    )

    with tab_res:
        present = rounds_present(fixtures) or [1]
        rnd = st.selectbox("Kolo", present, key="admin_res_round")
        fs = round_fixtures(fixtures, rnd)
        df = pd.DataFrame([
            {"match_id": f["match_id"], "match": f"{f['home']} v {f['away']}",
             "home_score": f.get("home_score"), "away_score": f.get("away_score")}
            for f in fs
        ])
        edited = st.data_editor(
            df, hide_index=True, use_container_width=True, key=f"res_ed_{rnd}",
            disabled=["match_id", "match"],
            column_config={
                "match_id": st.column_config.TextColumn("ID zápasu"),
                "match": st.column_config.TextColumn("Zápas"),
                "home_score": st.column_config.NumberColumn("Domácí", min_value=0, max_value=30),
                "away_score": st.column_config.NumberColumn("Hosté", min_value=0, max_value=30),
            },
        )
        if st.button("Uložit výsledky", type="primary"):
            try:
                save_results(rnd, edited)
            except PredictionError as e:
                st.error(str(e))
            except Exception:  # noqa: BLE001
                st.error("Nepodařilo se uložit výsledky (Google Sheets).")
            else:
                st.success(f"Výsledky kola {rnd} byly uloženy. Tabulka se přepočítala.")

    with tab_fix:
        present_now = rounds_present(fixtures)
        missing = [r for r in sorted(SEASON_FIXTURES) if r not in present_now]
        st.markdown("**Oficiální zápasy (kola 1–8)**")
        if missing:
            st.caption(f"Kola, která zatím nejsou v tabulce: {', '.join(f'K{r}' for r in missing)}.")
        else:
            st.caption("Všech 8 oficiálních kol už je v tabulce. ✅")
        if st.button("Doplnit oficiální zápasy (kola 1–8)"):
            added = seed_fixtures(get_spreadsheet())
            refresh()
            if added:
                st.success(f"Přidáno {added} zápasů. Existující kola zůstala beze změny.")
                st.rerun()
            else:
                st.info("Není co přidat — všech 8 kol už je založeno.")

        st.divider()
        st.markdown("**Ručně přidat vlastní kolo**")
        new_rnd = st.number_input("Číslo kola", 1, TOTAL_ROUNDS,
                                  min(len(rounds_present(fixtures)) + 1, TOTAL_ROUNDS))
        st.caption("Formát výkopu: RRRR-MM-DDTHH:MM (pražský čas).")
        blank = pd.DataFrame([{"kickoff": "", "home": "", "away": ""} for _ in range(10)])
        new_fx = st.data_editor(
            blank,
            hide_index=True,
            use_container_width=True,
            num_rows="dynamic",
            key=f"fix_ed_{new_rnd}",
            column_config={
                "kickoff": st.column_config.TextColumn("Výkop"),
                "home": st.column_config.TextColumn("Domácí"),
                "away": st.column_config.TextColumn("Hosté"),
            },
        )
        if st.button("Přidat tyto zápasy"):
            added = add_round_fixtures(int(new_rnd), new_fx)
            st.success(f"Do kola {int(new_rnd)} bylo přidáno {added} zápasů.") if added \
                else st.warning("Nebyl vyplněn žádný platný řádek.")

    with tab_ply:
        st.caption("Upravuj jména hráčů, počet žolíků a stav **aktivní**. "
                   "Neaktivní hráči se nezobrazují v tabulce, výsledcích ani při zadávání tipů. "
                   "Stejné údaje lze upravit také přímo v Google tabulce.")
        pdf = pd.DataFrame(players)
        for col, default in (("zoliky", DEFAULT_ZOLIKY), ("active", "yes"), ("name", ""), ("code", "")):
            if col not in pdf.columns:
                pdf[col] = default
        pdf["zoliky"] = pd.to_numeric(pdf["zoliky"], errors="coerce").fillna(DEFAULT_ZOLIKY).astype(int)
        pdf["active"] = [player_active(r) for _, r in pdf.iterrows()]  # bool for checkbox editor
        pdf = pdf[["code", "name", "zoliky", "active"]]
        edited_p = st.data_editor(
            pdf, hide_index=True, use_container_width=True,
            disabled=["code"], key="ply_ed",
            column_config={
                "code": st.column_config.TextColumn("Kód"),
                "name": st.column_config.TextColumn("Jméno"),
                "zoliky": st.column_config.NumberColumn("Žolíky", min_value=0,
                                                        max_value=MAX_ZOLIKY, step=1),
                "active": st.column_config.CheckboxColumn("Aktivní"),
            },
        )
        if st.button("Uložit hráče"):
            try:
                changed_cells = save_player_names(edited_p, pdf)
            except PredictionError as e:
                st.error(str(e))
            except Exception:  # noqa: BLE001
                st.error("Nepodařilo se uložit hráče (Google Sheets).")
            else:
                if changed_cells:
                    st.success("Změny hráčů byly bezpečně uloženy.")
                else:
                    st.info("Nejsou žádné změny k uložení.")

    with tab_reg:
        st.caption("Registrace hráčů. Po přijetí platby přidej hráče do tabulky tlačítkem níže.")
        registrations = load_registrations()
        if not registrations:
            st.info("Zatím žádné registrace.")
        else:
            reg_df = pd.DataFrame(registrations).rename(columns={
                "name": "Jméno",
                "code": "Kód",
                "email": "E-mail",
                "created_at": "Vytvořeno",
                "status": "Stav",
            })
            st.dataframe(reg_df, hide_index=True, use_container_width=True)
            existing_codes = {norm_code(p["code"]) for p in players}
            pending = [r for r in registrations
                       if norm_code(r.get("code", "")) not in existing_codes]
            if pending:
                labels = {f"{r['name']} ({norm_code(r['code'])})": r for r in pending}
                choice = st.selectbox("Přidat registrovaného hráče do tabulky",
                                      list(labels.keys()), key="reg_add_sel")
                if st.button("Přidat jako hráče (3 žolíky)", type="primary"):
                    r = labels[choice]
                    added = add_player(r["code"], str(r["name"]).strip())
                    if added:
                        st.success(f"Hráč {r['name']} ({norm_code(r['code'])}) přidán do tabulky.")
                        st.rerun()
                    else:
                        st.warning("Tento kód už v tabulce existuje.")
            else:
                st.caption("Všichni registrovaní hráči už jsou v tabulce.")


def zolik_panel(players, predictions):
    players = active_players(players)
    zmap = canonical_zolik_map(players, predictions)

    participant_count = len(players)
    purchased_zoliky = sum(
        max(player_zoliky(players, p["code"]) - DEFAULT_ZOLIKY, 0)
        for p in players
    )
    entry_bank = participant_count * BANK_PER_PLAYER
    zolik_bank = purchased_zoliky * ZOLIK_PRICE
    total_bank = entry_bank + zolik_bank

    first_prize = int(total_bank * PRIZE_SPLIT[0])
    second_prize = int(total_bank * PRIZE_SPLIT[1])
    third_prize = total_bank - first_prize - second_prize

    def czk(value):
        return f"{int(value):,}".replace(",", " ") + " Kč"

    st.markdown(
        f"""
        <div class="prize-hero">
          <div class="eyebrow">Premier League tipovačka</div>
          <h2>Výhry a žolíci</h2>
          <p>Aktuální výherní fond a přehled žolíků všech aktivních hráčů.</p>
        </div>

        <div class="bank-grid">
          <div class="bank-stat">
            <div class="label">Počet účastníků</div>
            <div class="value">{participant_count}</div>
          </div>
          <div class="bank-stat">
            <div class="label">Dokoupené žolíky</div>
            <div class="value">{purchased_zoliky}</div>
          </div>
          <div class="bank-stat total">
            <div class="label">Celkový bank</div>
            <div class="value">{czk(total_bank)}</div>
          </div>
        </div>

        <div class="prize-grid">
          <div class="prize-card first">
            <div class="place">1. místo</div>
            <div class="amount">{czk(first_prize)}</div>
            <div class="share">50 % výherního fondu</div>
          </div>
          <div class="prize-card second">
            <div class="place">2. místo</div>
            <div class="amount">{czk(second_prize)}</div>
            <div class="share">30 % výherního fondu</div>
          </div>
          <div class="prize-card third">
            <div class="place">3. místo</div>
            <div class="amount">{czk(third_prize)}</div>
            <div class="share">20 % výherního fondu</div>
          </div>
        </div>

        <div class="calculation-note">
          Výpočet: {participant_count} × {BANK_PER_PLAYER} Kč + {purchased_zoliky} × {ZOLIK_PRICE} Kč
          = <b>{czk(total_bank)}</b>. Za dokoupené se počítají všechny přidělené žolíky nad základní 3 na aktivního hráče.
        </div>

        <div class="section-kicker">Přehled hráčů</div>
        <div class="section-title">Žolíci</div>
        <div class="section-copy">
          Každý hráč začíná se 3 žolíky. Jeden platně použitý žolík zdvojnásobí body za vybraný zápas.
        </div>
        """,
        unsafe_allow_html=True,
    )

    body = []
    for pl in players:
        code = norm_code(pl["code"])
        name = html.escape(str(pl["name"]))
        info = zmap.get(
            code,
            {"granted": player_zoliky(players, code), "counted": set(), "used_total": 0},
        )
        granted = info["granted"]
        counted = len(info["counted"])
        used_total = info["used_total"]
        remaining = max(granted - counted, 0)

        if used_total > granted:
            note = (
                f'<span class="joker-warning">{used_total - granted} nad limit — ignorováno</span>'
            )
        else:
            note = '<span class="joker-ok">V pořádku</span>'

        body.append(
            f"<tr><td class='name'>{name}</td>"
            f"<td class='number'>{granted}</td>"
            f"<td class='number'>{counted}</td>"
            f"<td class='number'><span class='joker-remaining'>{remaining}</span></td>"
            f"<td>{note}</td></tr>"
        )

    if not body:
        body.append(
            "<tr><td colspan='5' style='text-align:center;color:#9A8DA9;padding:22px'>"
            "Zatím nejsou aktivní žádní hráči.</td></tr>"
        )

    st.markdown(
        "<div class='joker-card'><table class='joker-table'>"
        "<thead><tr><th>Hráč</th><th class='number'>Žolíky</th>"
        "<th class='number'>Použito</th><th class='number'>Zbývá</th><th>Poznámka</th></tr></thead>"
        f"<tbody>{''.join(body)}</tbody></table></div>",
        unsafe_allow_html=True,
    )


