def rules_panel():
    st.markdown(
        f"""
        <div class="rules">
          <h2>Pravidla Premier League tipovačky</h2>

          <div class="example">
            Tipovačka probíhá v kolech zveřejněných v aplikaci. Aktuální ročník má
            <b>{TOTAL_ROUNDS} kol</b>. Oficiálním místem pro registraci, zadávání tipů,
            výsledky, pořadí a přehled žolíků je tato aplikace.
          </div>

          <h3>1 · Registrace a účast</h3>
          <p><b>1.1</b> — Soutěže se může účastnit pouze registrovaný a aktivovaný hráč.</p>
          <p><b>1.2</b> — Registrace se odesílá v záložce <b>„Registrace“</b>. Hráč si zvolí
          unikátní kód o délce 3–20 znaků; povolena jsou pouze písmena a číslice.</p>
          <p><b>1.3</b> — Hráč je aktivován po přijetí platby a potvrzení pořadatelem.
          Teprve aktivní hráč může ukládat tipy a je zahrnut do pořadí.</p>
          <p><b>1.4</b> — Hráč odpovídá za uchování svého hráčského kódu. Kdo kód zná,
          může před uzamčením kola změnit uložené tipy daného hráče.</p>
          <p><b>1.5</b> — Hráč přidaný až v průběhu soutěže získává body pouze za kola,
          která může po aktivaci řádně natipovat. Body za dříve uzamčená kola se nedoplňují.</p>

          <h3>2 · Startovné a výherní fond</h3>
          <p><b>2.1</b> — Startovné činí <b>850 Kč</b>: 750 Kč jde do výherního fondu
          a 100 Kč tvoří organizační poplatek.</p>
          <p><b>2.2</b> — Platba se provádí přes QR kód v záložce <b>„Registrace“</b>
          nebo jiným způsobem potvrzeným pořadatelem.</p>
          <p><b>2.3</b> — Výherní fond se rozdělí mezi první tři hráče v poměru
          <b>50 % / 30 % / 20 %</b>.</p>
          <p><b>2.4</b> — Aktuální fond v záložce <b>„Výhry a Žolíci“</b> se počítá jako
          počet aktivních hráčů × 750 Kč plus počet přidělených žolíků nad základní tři
          × 50 Kč. Zobrazené výhry se podle tohoto fondu přepočítávají automaticky.</p>
          <p><b>2.5</b> — Po aktivaci hráče se startovné nevrací. Výjimkou je zrušení
          celé tipovačky pořadatelem před jejím zahájením.</p>
          <p><b>2.6</b> — Minimální počet účastníků je 10. Pokud se tento počet nenaplní,
          pořadatel může soutěž před zahájením zrušit a přijaté startovné vrátit.</p>
          <p><b>2.7</b> — Pořadatel se soutěže jako hráč neúčastní.</p>

          <h3>3 · Zadávání tipů</h3>
          <p><b>3.1</b> — Tipy se zadávají výhradně v záložce
          <b>„Zadat tipy“</b>. Hráč zadá svůj kód, vybere kolo
          a vyplní přesné skóre každého zápasu.</p>
          <p><b>3.2</b> — Pro uložení kola musí být vyplněny oba údaje skóre u všech zápasů.
          Hodnota 0 je platný tip. Částečně vyplněné kolo aplikace neuloží.</p>
          <p><b>3.3</b> — Tipy lze do uzamčení opakovaně měnit. Platí vždy poslední
          úspěšně uložená verze.</p>
          <p><b>3.4</b> — Celé kolo se uzamkne v okamžiku výkopu prvního zápasu daného kola,
          vždy podle času <b>Europe/Prague</b>. Uzamčení se vztahuje i na zápasy,
          které začínají později.</p>
          <p><b>3.5</b> — Po uzamčení nelze tipy doplnit, změnit ani přijmout jiným kanálem.
          Hráč má proto uložit tipy s dostatečnou časovou rezervou.</p>
          <p><b>3.6</b> — Neuložený tip se po vyhodnocení zápasu počítá jako 0 bodů.</p>
          <p><b>3.7</b> — Tipy ostatních hráčů jsou do uzamčení kola skryté. Po uzamčení
          se zobrazí v záložce <b>„Výsledky“</b>.</p>
          <p><b>3.8</b> — Pokud je zápas odložen, uložený tip zůstává platný a vyhodnotí se
          po odehrání, pokud pořadatel předem neoznámí jiné řešení. Definitivně zrušený zápas
          se neboduje.</p>

          <h3>4 · Bodování zápasů</h3>
          <p><b>4.1</b> — Přesně trefené skóre = <b>3 body</b>.
          Příklad: tip 2:1, výsledek 2:1.</p>
          <p><b>4.2</b> — Správný rozdíl skóre = <b>2 body</b>.
          Příklad: tip 2:1, výsledek 1:0. U remíz se počítá rozdíl 0,
          takže tip 1:1 při výsledku 2:2 získá 2 body.</p>
          <p><b>4.3</b> — Správný výsledek utkání, ale chybný rozdíl skóre = <b>1 bod</b>.
          Příklad: tip 2:1, výsledek 3:1.</p>
          <p><b>4.4</b> — Chybný vítěz nebo chybná remíza = <b>0 bodů</b>.</p>
          <p><b>4.5</b> — Používá se oficiální konečný výsledek ligového utkání po
          90 minutách včetně nastavení.</p>
          <p><b>4.6</b> — Dokud pořadatel nezadá skutečný výsledek, zápas se do bodů
          nezapočítá. Po zadání nebo opravě výsledku aplikace pořadí automaticky přepočítá.</p>

          <h3>5 · Pořadí a rozhodování shod</h3>
          <p><b>5.1</b> — O pořadí rozhoduje nejprve celkový počet bodů.</p>
          <p><b>5.2</b> — Při shodě rozhoduje postupně: 1. více přesně trefených skóre,
          2. více trefených rozdílů skóre, 3. los pořadatele.</p>
          <p><b>5.3</b> — Žolík zdvojnásobuje pouze body za zápas. Počet přesných skóre
          ani počet trefených rozdílů pro rozhodování shod nezdvojnásobuje.</p>
          <p><b>5.4</b> — Pokud zůstává úplná shoda, aplikace může hráče dočasně zobrazit
          v technickém pořadí. Konečné pořadí pro výplatu určí až los podle bodu 5.2.</p>

          <h3>6 · Žolíky</h3>
          <p><b>6.1</b> — Každý hráč dostane při aktivaci <b>3 žolíky</b>.</p>
          <p><b>6.2</b> — Lze dokoupit maximálně 10 dalších žolíků za 50 Kč za kus.
          Jeden hráč tak může mít nejvýše 13 žolíků.</p>
          <p><b>6.3</b> — Dokoupený žolík je možné použít až po přijetí platby a navýšení
          limitu pořadatelem v aplikaci.</p>
          <p><b>6.4</b> — Poslední možnost nákupu je 10 minut před uzamčením posledního kola
          tipovačky.</p>
          <p><b>6.5</b> — Žolík se použije zaškrtnutím pole <code>Ž 2×</code> u konkrétního
          zápasu před uzamčením kola. Na jeden zápas lze použít nejvýše jeden žolík.</p>
          <p><b>6.6</b> — Žolík zdvojnásobí získané body za daný zápas: 3 → 6, 2 → 4,
          1 → 2 a 0 zůstává 0.</p>
          <p><b>6.7</b> — Platně použitý žolík je v záložce <b>„Výsledky“</b> označen
          růžovým nebo červeným zvýrazněním celého řádku.</p>
          <p><b>6.8</b> — Přehled přidělených, použitých a zbývajících žolíků je v záložce
          <b>„Výhry a Žolíci“</b>.</p>
          <p><b>6.9</b> — Aplikace nepovolí uložit více žolíků, než má hráč k dispozici.
          Případný historický výběr nad limit se pro bodování ignoruje.</p>
          <p><b>6.10</b> — Žolíky jsou nepřenosné. Nevyužité žolíky po skončení soutěže
          propadají a jejich cena se nevrací.</p>
          <p><b>6.11</b> — Veškeré platby za dokoupené žolíky se přidávají do výherního fondu.</p>

          <h3>7 · Provoz aplikace a opravy</h3>
          <p><b>7.1</b> — Aplikace je hlavním rozhraním soutěže, ale nepřetržitá dostupnost
          24/7 není garantována. Hráč má své tipy uložit včas a zkontrolovat potvrzení o uložení.</p>
          <p><b>7.2</b> — Při technickém problému musí hráč kontaktovat pořadatele co nejdříve,
          ideálně ještě před uzamčením kola, a doložit problém například snímkem obrazovky.
          Samotná zpráva odeslaná po uzamčení automaticky nezakládá nárok na doplnění tipu.</p>
          <p><b>7.3</b> — Oficiální výsledky, hráče, jejich aktivitu a počet žolíků spravuje
          pouze pořadatel. Běžný hráč nemá přístup k administrační části.</p>
          <p><b>7.4</b> — Prokazatelná chyba ve výsledku, výpočtu nebo datech bude opravena
          podle těchto pravidel. Oprava může změnit již zobrazené body a pořadí.</p>

          <h3>8 · Změny pravidel a spory</h3>
          <p><b>8.1</b> — Podstatná změna pravidel musí být oznámena před uzamčením kola,
          kterého se týká. Změny se nepoužijí zpětně na již uzamčená kola, s výjimkou opravy
          zjevné chyby nebo rozporu.</p>
          <p><b>8.2</b> — Námitku k výsledku nebo bodování je vhodné uplatnit do 48 hodin
          od zveřejnění či opravy výsledku.</p>
          <p><b>8.3</b> — Situace, kterou pravidla výslovně neřeší, posoudí pořadatel tak,
          aby zachoval stejné podmínky pro všechny hráče a integritu soutěže.</p>
        </div>
        """,
        unsafe_allow_html=True,
    )

def _valid_email(s):
    s = str(s).strip()
    if s.count("@") != 1:
        return False
    local, _, domain = s.partition("@")
    return bool(local) and "." in domain and not domain.startswith(".") \
        and not domain.endswith(".") and len(s) >= 5


def _valid_code(s):
    s = str(s).strip()
    return s.isalnum() and 3 <= len(s) <= 20


def _validated_qr_bytes(value):
    """Return valid image bytes for a Base64 QR value, otherwise None."""
    try:
        raw = base64.b64decode(str(value), validate=True)
        with Image.open(BytesIO(raw)) as image:
            image.verify()
        return raw
    except Exception:  # invalid/truncated Base64 or image data
        return None


def render_payment_qr():
    """Render the payment QR without allowing a broken image to crash the app.

    Preferred setup: save a real QR image as ``qr_platba.png`` in the same
    directory as this Python file and commit both files to the repository.
    """
    app_dir = Path(__file__).resolve().parent
    for filename in ("qr_platba.png", "qr_platba.jpg", "qr_platba.jpeg", "qr_platba.webp"):
        qr_path = app_dir / filename
        if qr_path.is_file():
            try:
                with Image.open(qr_path) as image:
                    image.verify()
                st.image(str(qr_path), width=230, caption="QR Platba")
                return True
            except Exception:
                continue

    # Optional deployment-friendly Base64 value in .streamlit/secrets.toml:
    # [app]
    # qr_payment_b64 = "..."
    try:
        secret_b64 = st.secrets.get("app", {}).get("qr_payment_b64", "")
    except Exception:
        secret_b64 = ""

    for candidate in (secret_b64, QR_PLATBA_B64):
        if not candidate:
            continue
        qr_bytes = _validated_qr_bytes(candidate)
        if qr_bytes is not None:
            st.image(qr_bytes, width=230, caption="QR Platba")
            return True

    st.warning(
        "QR obrázek je poškozený. Ulož platný obrázek jako `qr_platba.png` "
        "do stejné složky jako `app.py` a nasaď oba soubory."
    )
    return False


def registration_panel(players, registrations):
    st.markdown("<div class='rules'><h2>Registrace</h2></div>", unsafe_allow_html=True)
    st.write("Vyplň registraci a následně zaplať startovné pomocí QR kódu níže. "
             "Do tipovačky tě přidá pořadatel po přijetí platby (viz pravidlo 1.3).")

    taken = {norm_code(p["code"]) for p in players}
    taken |= {norm_code(r.get("code", "")) for r in registrations}

    col_form, col_qr = st.columns([1.2, 1])

    with col_form:
        name = st.text_input("Jméno a příjmení", key="reg_name", placeholder="např. Jan Novák")
        code = st.text_input("Zvol si svůj hráčský kód", key="reg_code",
                             placeholder="např. JANN (3–20 znaků, jen písmena a čísla)")
        email = st.text_input("E-mail", key="reg_email", placeholder="např. jan@email.cz")

        if st.button("Odeslat registraci", type="primary"):
            problems = []
            if not str(name).strip():
                problems.append("Vyplň jméno.")
            if not _valid_code(code):
                problems.append("Kód musí mít 3–20 znaků, jen písmena a čísla (bez mezer).")
            elif norm_code(code) in taken:
                problems.append("Tento kód už je zabraný — zvol si jiný.")
            if not _valid_email(email):
                problems.append("Zadej platný e-mail.")

            if problems:
                for p in problems:
                    st.error(p)
            else:
                try:
                    save_registration(str(name).strip(), str(code).strip(), str(email).strip())
                except Exception:  # noqa: BLE001
                    st.error("Registraci se nepodařilo uložit (Google Sheets). Zkus to znovu.")
                else:
                    st.success(f"Registrace odeslána, {str(name).strip()}! Kód: "
                               f"**{norm_code(code)}**. Nyní prosím zaplať startovné QR kódem vpravo.")

    with col_qr:
        st.markdown("<div style='text-align:center'>", unsafe_allow_html=True)
        render_payment_qr()
        st.markdown(
            "<div style='text-align:center;font-size:.9rem'>"
            "<b>Startovné 850 Kč</b><br>"
            "<span style='color:#666'>750 Kč do banku · 100 Kč poplatek</span></div>",
            unsafe_allow_html=True,
        )
        st.markdown("</div>", unsafe_allow_html=True)

    st.caption("Po aktivaci se startovné nevrací; výjimka při zrušení soutěže je popsána v pravidle 2.5.")


