def game_panel(players, fixtures, predictions):
    """Competition overview shown on the first top-level tab."""
    rnd = active_round(fixtures)
    dl = round_deadline(fixtures, rnd)
    if dl is not None:
        countdown_component(dl, rnd, fixtures)

    st.markdown("### Tabulka")
    render_leaderboard(players, fixtures, predictions)


def organiser_access_panel(players, fixtures, predictions, fix_problems, ply_problems):
    """Password-gated organiser tools shown on the final top-level tab."""
    code = st.text_input("Kód organizátora", type="password", key="admin_code_in")
    if code and code == st.secrets["app"].get("admin_code"):
        admin_panel(players, fixtures, predictions, fix_problems, ply_problems)
    elif code:
        st.error("Nesprávný kód organizátora.")
    else:
        st.info("Pro správu výsledků a hráčů zadej kód organizátora.")


def main():
    inject_css()

    try:
        sh = bootstrap()
    except Exception as e:  # noqa: BLE001
        st.error("Nepodařilo se připojit ke Google tabulce. Zkontroluj nastavení secrets a ověř, "
                 "že je tabulka sdílena s e-mailem servisního účtu s rolí Editor.")
        # Deliberately do NOT dump the exception — it can contain service-account details.
        st.stop()

    players_raw = load_players()
    fixtures_raw = load_fixtures()
    predictions = load_predictions()
    registrations = load_registrations()

    # Validate before any player-facing use. Keep valid rows usable; surface the rest.
    players, ply_problems = validate_players(players_raw)
    fixtures, fix_problems, rounds_with_issues = validate_fixtures(fixtures_raw)

    st.markdown(
        f"""
        <div class='hero'>
          <div class='hero-inner'>
            <img class='hero-logo' src='data:image/svg+xml;base64,{PL_LOGO_B64}' alt='Logo Premier League'>
            <div class='hero-copy'>
              <h1>Tipovačka 2026/27</h1>
            </div>
          </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    (
        tab_game,
        tab_predictions,
        tab_results,
        tab_rules,
        tab_zolik,
        tab_reg,
        tab_admin,
    ) = st.tabs(
        [
            "Tabulka",
            "Zadat tipy",
            "Výsledky",
            "Pravidla",
            "Výhry a Žolíci",
            "Registrace",
            "Organizátor",
        ]
    )

    with tab_game:
        game_panel(players, fixtures, predictions)
    with tab_predictions:
        predictions_panel(players, fixtures, predictions, rounds_with_issues)
    with tab_results:
        results_panel(players, fixtures, predictions, rounds_with_issues)
    with tab_rules:
        rules_panel()
    with tab_zolik:
        zolik_panel(players, predictions)
    with tab_reg:
        registration_panel(players, registrations)
    with tab_admin:
        organiser_access_panel(players, fixtures, predictions, fix_problems, ply_problems)


if __name__ == "__main__":
    main()
